import ldap

def search_users_by_username(ldap_server, username):
    try:
        # Connect to the LDAP server
        l = ldap.initialize(f"ldap://{ldap_server}")
        
        # Bind to the server (replace 'cn=admin,dc=example,dc=com' and 'password' with your credentials)
        l.simple_bind_s('cn=admin,dc=example,dc=com', 'password')
        
        # Search for users by username
        search_base = "ou=users,dc=example,dc=com"
        search_filter = f"(uid={username})"
        attributes = ['uid', 'cn', 'mail']
        
        result = l.search_s(search_base, ldap.SCOPE_SUBTREE, search_filter, attributes)
        
        if len(result) > 0:
            user_info = result[0][1]
            print(f"User found: UID={user_info['uid'][0].decode('utf-8')}, CN={user_info['cn'][0].decode('utf-8')}, Email={user_info.get('mail', [''])[0].decode('utf-8')}")
        else:
            print("User not found.")
        
        # Close the connection
        l.unbind_s()
    
    except ldap.LDAPError as e:
        print(f"LDAP error: {e}")

# Example usage
search_users_by_username('ldap.example.com', 'johndoe')